module main ();
         reg clk = 0;
         reg [3:0] counter = 0;
         integer l2;
         function log2 (input [3:0] x);
                 integer log2 = (x < 2) ? 1 : (x < 4) ? 2 : (x < 8) ? 3 : 4;
         endfunction
         always @(posedge clk) begin
                 counter <= counter + 1;
                 l2 <= log2(counter);
                 // this works:
                 $display("log2(%d) == %d", counter, l2);
                 // this fails (%Error: Internal Error: Function not underneath a statement):
                 //$display("log2(%d) == %d", counter, log2(counter));
         end
endmodule


